/*
  # Redesign trial_ending Email Template

  1. Changes
    - Completely redesigned trial_ending (de) email
    - New subject and preheader
    - Calm, professional tone – no panic, clear value communication
    - Hero section: "Ihre Pro-Testphase endet bald"
    - Three feature blocks showing what will no longer be available:
      Block 1: Überblick & Finanzen (Bankabgleich, Cashflow/Anlage V, Mahnwesen/Indexmiete)
      Block 2: Kommunikation & Zusammenarbeit (Ticketsystem, Mieterportal, Multi-User)
      Block 3: Dokumente & Abrechnung (Betriebskosten, Dokument-Assistent, Prioritäts-Support)
    - Reassuring info box: "Ihre Daten bleiben erhalten"
    - Clear CTA: "Jetzt Pro behalten" with subtle price hint
    - Updated plain text version with proper Umlaute
    - Keeps existing header/footer structure

  2. Security
    - No schema changes, data-only update
*/

DO $$
DECLARE
  v_html text;
  v_text text;
BEGIN

v_html := E'<!DOCTYPE html>\n<html lang="de">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<meta http-equiv="X-UA-Compatible" content="IE=edge">\n<title>Ihre Pro-Testphase endet bald</title>\n</head>\n<body style="margin: 0; padding: 0; background-color: #f5f5f5; font-family: ''Manrope'', Arial, Helvetica, sans-serif; -webkit-text-size-adjust: none; text-size-adjust: none;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f5f5f5;">\n<tr><td align="center" style="padding: 32px 16px;">\n<table width="600" border="0" cellpadding="0" cellspacing="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden;">\n\n<!-- HEADER -->\n<tr><td style="padding: 28px 32px 20px; text-align: center; border-bottom: 1px solid #eee;">\n<a href="https://rentab.ly" target="_blank" style="display: inline-block;">\n<img src="https://6f36f82794.imgdist.com/pub/bfra/2bnm3c1v/dzm/8g5/nzj/rentably-logo.svg" alt="rentably" width="180" style="display: block; height: auto; border: 0;" />\n</a>\n</td></tr>\n\n<!-- HERO -->\n<tr><td style="padding: 36px 32px 0;">\n<h1 style="margin: 0 0 16px; color: #1E1E24; font-size: 22px; font-weight: 700; line-height: 1.35;">Ihre Pro-Testphase endet bald</h1>\n<p style="margin: 0 0 8px; color: #555; font-size: 14px; line-height: 1.65;">Hallo <strong style="color: #1E1E24;">{{userName}}</strong>,</p>\n<p style="margin: 0; color: #555; font-size: 14px; line-height: 1.65;">Ihre 30-t&auml;gige Testphase endet in <strong style="color: #1E1E24;">{{days_remaining}} Tagen</strong> am <strong style="color: #1E1E24;">{{trial_end_date}}</strong>. Danach wird Ihr Account automatisch auf den Basic-Tarif umgestellt. Ihre Daten bleiben vollst&auml;ndig erhalten &ndash; allerdings stehen Ihnen mehrere Pro-Funktionen dann nicht mehr zur Verf&uuml;gung.</p>\n</td></tr>\n\n<!-- SECTION TITLE -->\n<tr><td style="padding: 32px 32px 0; text-align: center;">\n<p style="margin: 0 0 4px; color: #1E1E24; font-size: 16px; font-weight: 700;">Diese Funktionen entfallen im Basic-Tarif</p>\n<p style="margin: 0; color: #888; font-size: 13px;">Folgende Bereiche sind nach dem Downgrade nicht mehr verf&uuml;gbar.</p>\n</td></tr>\n\n<!-- BLOCK 1: FINANZEN -->\n<tr><td style="padding: 20px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #FEF3F2; border: 1px solid #fecdca; text-align: center; line-height: 32px; font-size: 15px; color: #d97757;">&#10005;</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 10px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">&Uuml;berblick &amp; Finanzen</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 5px;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Automatischer Bankabgleich</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Cashflow, Finanzanalyse &amp; Anlage V</span></td></tr>\n<tr><td style="padding: 0;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Mahnwesen &amp; Indexmiete</span></td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- BLOCK 2: KOMMUNIKATION -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #FEF3F2; border: 1px solid #fecdca; text-align: center; line-height: 32px; font-size: 15px; color: #d97757;">&#10005;</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 10px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Kommunikation &amp; Zusammenarbeit</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 5px;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Ticketsystem &amp; Nachrichten</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Mieterportal</span></td></tr>\n<tr><td style="padding: 0;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Multi-User-Konten</span></td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- BLOCK 3: DOKUMENTE -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #FEF3F2; border: 1px solid #fecdca; text-align: center; line-height: 32px; font-size: 15px; color: #d97757;">&#10005;</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 10px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Dokumente &amp; Abrechnung</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 5px;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Betriebskostenabrechnung</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Dokument-Assistent</span></td></tr>\n<tr><td style="padding: 0;"><span style="color: #d97757; font-size: 12px; margin-right: 6px;">&#10005;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Priorit&auml;ts-Support (24h)</span></td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- DATA SAFE INFO BOX -->\n<tr><td style="padding: 24px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f0fdf4; border-radius: 8px; border-left: 4px solid #22c55e;">\n<tr><td style="padding: 18px 20px;">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 14px; font-weight: 700;">Ihre Daten bleiben erhalten</p>\n<p style="margin: 0; color: #555; font-size: 13px; line-height: 1.6;">Auch nach dem Ende Ihrer Testphase bleibt Ihr Account vollst&auml;ndig bestehen. Alle Basic-Funktionen k&ouml;nnen Sie weiterhin nutzen. Wenn Sie Pro-Funktionen weiter verwenden m&ouml;chten, k&ouml;nnen Sie jederzeit upgraden.</p>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- CTA -->\n<tr><td style="padding: 32px 32px 0; text-align: center;">\n<p style="margin: 0 0 20px; color: #555; font-size: 14px; line-height: 1.6;">Bleiben Sie im Pro-Tarif, wenn Sie weiterhin mit allen erweiterten Funktionen arbeiten m&ouml;chten.</p>\n<a href="{{upgrade_link}}" style="display: inline-block; background-color: #3c8af7; color: #ffffff; text-decoration: none; padding: 13px 40px; border-radius: 8px; font-size: 15px; font-weight: 700; letter-spacing: 0.01em;">Jetzt Pro behalten</a>\n<p style="margin: 12px 0 0; color: #999; font-size: 12px;">Pro ab 9,00 &euro; pro Monat &middot; jederzeit k&uuml;ndbar</p>\n</td></tr>\n\n<!-- SUPPORT -->\n<tr><td style="padding: 32px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 24px 0 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 18px 20px;">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 14px; font-weight: 700;">Fragen?</p>\n<p style="margin: 0 0 10px; color: #666; font-size: 13px; line-height: 1.6;">Wir helfen Ihnen gerne weiter &ndash; auch bei der Entscheidung, welcher Tarif am besten zu Ihnen passt.</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #555; font-size: 13px;">E-Mail: <a href="mailto:hallo@rentab.ly" style="color: #3c8af7; text-decoration: none; font-weight: 600;">hallo@rentab.ly</a></td></tr>\n<tr><td style="padding: 0; color: #555; font-size: 13px;">WhatsApp: <a href="https://wa.me/493022334468" style="color: #3c8af7; text-decoration: none; font-weight: 600;">+49 30 2233 4468</a></td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- SPACER -->\n<tr><td style="padding: 8px 0 0;">&nbsp;</td></tr>\n\n<!-- FOOTER -->\n<tr><td style="padding: 20px 32px; border-top: 1px solid #eee; text-align: center;">\n<p style="margin: 0 0 4px; color: #999; font-size: 12px;">&copy; 2026 <a href="https://rentab.ly" style="color: #3c8af7; text-decoration: none;">rentably</a></p>\n<p style="margin: 0 0 8px; color: #bbb; font-size: 11px; line-height: 1.5;">Sie erhalten diese E-Mail, weil Sie als Nutzer bei rentably angemeldet sind.</p>\n<p style="margin: 0 0 6px; color: #bbb; font-size: 11px; line-height: 1.8;"><a href="mailto:hallo@rentab.ly" style="color: #3c8af7; text-decoration: none;">hallo@rentab.ly</a>&nbsp;&nbsp;|&nbsp;&nbsp;<a href="https://wa.me/493022334468" style="color: #3c8af7; text-decoration: none;">WhatsApp</a>&nbsp;&nbsp;|&nbsp;&nbsp;Mo &ndash; Fr, 9:00 &ndash; 18:00 Uhr</p>\n<p style="margin: 0; color: #bbb; font-size: 11px; line-height: 1.5;"><a href="https://rentab.ly/datenschutz" style="color: #3c8af7; text-decoration: none;">Datenschutz</a>&nbsp;|&nbsp;<a href="https://rentab.ly/impressum" style="color: #3c8af7; text-decoration: none;">Impressum</a>&nbsp;|&nbsp;<a href="https://rentab.ly/kontakt" style="color: #3c8af7; text-decoration: none;">Kontakt</a></p>\n</td></tr>\n\n</table>\n</td></tr>\n</table>\n</body>\n</html>';

v_text := E'Ihre Pro-Testphase endet bald\n\nHallo {{userName}},\n\nIhre 30-tägige Testphase endet in {{days_remaining}} Tagen am {{trial_end_date}}. Danach wird Ihr Account automatisch auf den Basic-Tarif umgestellt. Ihre Daten bleiben vollständig erhalten – allerdings stehen Ihnen mehrere Pro-Funktionen dann nicht mehr zur Verfügung.\n\n\nDIESE FUNKTIONEN ENTFALLEN IM BASIC-TARIF\n==========================================\n\nÜberblick & Finanzen\n  x Automatischer Bankabgleich\n  x Cashflow, Finanzanalyse & Anlage V\n  x Mahnwesen & Indexmiete\n\nKommunikation & Zusammenarbeit\n  x Ticketsystem & Nachrichten\n  x Mieterportal\n  x Multi-User-Konten\n\nDokumente & Abrechnung\n  x Betriebskostenabrechnung\n  x Dokument-Assistent\n  x Prioritäts-Support (24h)\n\n\nIHRE DATEN BLEIBEN ERHALTEN\n---------------------------\nAuch nach dem Ende Ihrer Testphase bleibt Ihr Account vollständig bestehen. Alle Basic-Funktionen können Sie weiterhin nutzen. Wenn Sie Pro-Funktionen weiter verwenden möchten, können Sie jederzeit upgraden.\n\n\nBleiben Sie im Pro-Tarif, wenn Sie weiterhin mit allen erweiterten Funktionen arbeiten möchten.\n\n>> Jetzt Pro behalten: {{upgrade_link}}\n\nPro ab 9,00 EUR pro Monat – jederzeit kündbar\n\n\nFRAGEN?\nWir helfen Ihnen gerne weiter – auch bei der Entscheidung, welcher Tarif am besten zu Ihnen passt.\nE-Mail: hallo@rentab.ly\nWhatsApp: +49 30 2233 4468\n\n--\nrentably | hallo@rentab.ly | WhatsApp: https://wa.me/493022334468\nMo - Fr, 9:00 - 18:00 Uhr\nDatenschutz: https://rentab.ly/datenschutz | Impressum: https://rentab.ly/impressum | Kontakt: https://rentab.ly/kontakt';

UPDATE email_templates
SET
  subject = 'Ihre Pro-Testphase endet bald – diese Funktionen fallen weg',
  body_html = v_html,
  body_text = v_text,
  updated_at = now()
WHERE template_key = 'trial_ending' AND language = 'de';

END $$;
